#include <iostream>

int main()
{
    int n{};
    std::cin >> n;

    std::cout << "DEC: " << n << '\n';
    std::cout << std::showbase << std::oct << "OCT: " << n << '\n';
    std::cout << std::uppercase << std::hex << "HEX: " << n << '\n';

    return 0;
}

